import{_ as t,o as a,c as o,ag as i}from"./chunks/framework.B9unkguw.js";const h=JSON.parse('{"title":"视频","description":"","frontmatter":{},"headers":[],"relativePath":"zh/qgc-user-guide/fly_view/video.md","filePath":"zh/qgc-user-guide/fly_view/video.md"}'),r={name:"zh/qgc-user-guide/fly_view/video.md"};function l(s,e,n,d,c,p){return a(),o("div",null,e[0]||(e[0]=[i('<h1 id="视频" tabindex="-1">视频 <a class="header-anchor" href="#视频" aria-label="Permalink to &quot;视频&quot;">​</a></h1><p>当视频流启用时(应用程序设置-视频)， <em>QGroundControl</em> 将在地图底部的“视频切换窗口”中显示当前选中载具的视频流。 You can press the switcher anywhere to toggle <em>Video</em> and <em>Map</em> to foreground.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>视频流已配置/启用在 <a href="./../settings_view/general.html#video">应用程序设置 &gt; 常规 &gt; 视频</a>。</p></div><p>您可以在开关上使用控件来进一步配置视频显示：</p><ul><li>通过拖动右上角的图标来调整切换器的大小。</li><li>点击左下方的切换图标来隐藏切换器。</li><li>按下视频切换器窗口左上角的图标，将其分离 （分离后，你可以像操作操作系统中的其他窗口一样移动和调整该窗口的大小）。 如果您关闭分离的窗口，切换器将重新锁定到 QGC 飞行视图。</li></ul><h3 id="录像" tabindex="-1">录像 <a class="header-anchor" href="#录像" aria-label="Permalink to &quot;录像&quot;">​</a></h3><p>如果相机和载具支持，<em>QGroundControl</em> 可以在相机上开始和停止视频录制。 <em>QGroundControl</em> 也可以录制视频流并在本地保存。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>相机上存储的视频质量可能更高，但很可能你的地面站会有大得多的录制容量。</p></div><h4 id="录制视频流-gcs" tabindex="-1">录制视频流 (GCS) <a class="header-anchor" href="#录制视频流-gcs" aria-label="Permalink to &quot;录制视频流 (GCS)&quot;">​</a></h4><p>Video stream recording is controlled on the <a href="./hud.html#video_instrument_page">video stream instrument page</a>. 按下红色圆圈开始录制新视频(每次按下圆圈时创建新视频文件)； 正在录制时，圆圈将会变成红色正方形。</p><p>视频流录制已配置在 <a href="./../settings_view/general.html">应用程序设置 &gt; 常规</a>：</p><ul><li><p><a href="./../settings_view/general.html#video-recording">视频录制</a> - 指定录制文件格式和存储限制。</p><p>::: 信息 视频默认保存为 Matroska 格式 (.mkv) 。 这种格式在出现错误的情况下，相对不容易损坏。 :::</p></li><li><p><a href="./../settings_view/general.html#miscellaneous">杂项</a> - 流视频保存在<strong>应用程序加载/保存路径</strong>下。</p></li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>存储的视频仅包括视频流本身。 要使用显示的 QGroundControl 应用程序元素录制视频，您应该使用单独的屏幕录制软件。</p></div><h4 id="在相机上录制视频" tabindex="-1">在相机上录制视频 <a class="header-anchor" href="#在相机上录制视频" aria-label="Permalink to &quot;在相机上录制视频&quot;">​</a></h4><p>Start/stop video recording <em>on the camera itself</em> using the <a href="./hud.html#camera_instrument_page">camera instrument page</a>. 先切换到视频模式，然后选择红色按钮开始录制。</p>',15)]))}const u=t(r,[["render",l]]);export{h as __pageData,u as default};
